typedef struct {
    float weight;
    float _pad0;
    long assign;
    float cost;
    float _pad1;
} Point_Struct;

inline float compute_dist_to_x(__global const float *coord,
                               __local float *xcoord,
                               int num,
                               int dim,
                               int idx) {
    float result = 0.0f;
    for (int d = 0; d < dim; d++) {
        float diff = coord[d * num + idx] - xcoord[d];
        result += diff * diff;
    }
    return result;
}

inline void pgain_kernel_body(__global Point_Struct *p,
                              __global const float *coord,
                              __global float *work_mem,
                              __global const int *center_table,
                              __global char *switch_membership,
                              __local float *xcoord,
                              int num,
                              int dim,
                              long x,
                              int K) {
    int lid = (int)get_local_id(0);
    int lsize = (int)get_local_size(0);
    int gid = (int)get_global_id(0);

    for (int d = lid; d < dim; d += lsize) {
        xcoord[d] = coord[d * num + (int)x];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    if (gid >= num) return;

    float x_cost = compute_dist_to_x(coord, xcoord, num, dim, gid) * p[gid].weight;
    float current_cost = p[gid].cost;
    int base = gid * (K + 1);

    if (x_cost < current_cost) {
        switch_membership[gid] = '1';
        work_mem[base + K] = x_cost - current_cost;
    } else {
        int assign_idx = (int)p[gid].assign;
        int ct = center_table[assign_idx];
        work_mem[base + ct] = current_cost - x_cost;
    }
}

__kernel void kernel0(__global Point_Struct *p,
                      __global const float *coord,
                      __global float *work_mem,
                      __global const int *center_table,
                      __global char *switch_membership,
                      __local float *xcoord,
                      int num,
                      int dim,
                      long x,
                      int K) {
    pgain_kernel_body(p, coord, work_mem, center_table, switch_membership,
                      xcoord, num, dim, x, K);
}

__kernel void kernel1(__global Point_Struct *p,
                      __global const float *coord,
